export const DraggableNode = ({ type, label, icon: Icon, color = 'primary' }) => {
    const onDragStart = (event, nodeType) => {
      const appData = { nodeType }
      event.dataTransfer.setData('application/reactflow', JSON.stringify(appData));
      event.dataTransfer.effectAllowed = 'move';
    };

    const colorMap = {
        primary: 'bg-primary hover:bg-primary-hover border-primary/20 hover:border-primary/50 text-white',
        emerald: 'bg-emerald-500/10 hover:bg-emerald-500/20 border-emerald-500/20 hover:border-emerald-500/50 text-emerald-400',
        rose: 'bg-rose-500/10 hover:bg-rose-500/20 border-rose-500/20 hover:border-rose-500/50 text-rose-400',
        sky: 'bg-sky-500/10 hover:bg-sky-500/20 border-sky-500/20 hover:border-sky-500/50 text-sky-400',
        amber: 'bg-amber-500/10 hover:bg-amber-500/20 border-amber-500/20 hover:border-amber-500/50 text-amber-400',
        violet: 'bg-violet-500/10 hover:bg-violet-500/20 border-violet-500/20 hover:border-violet-500/50 text-violet-400',
    };

    const colorClass = colorMap[color] || colorMap.primary;

    return (
      <div
        className={`cursor-grab flex flex-col items-center justify-center min-w-[80px] h-20 p-3 rounded-xl border transition-all duration-300 hover:scale-105 active:scale-95 group ${colorClass}`}
        onDragStart={(event) => onDragStart(event, type)}
        onDragEnd={(event) => (event.target.style.cursor = 'grab')}
        draggable
      >
        <div className="mb-2 group-hover:scale-110 transition-transform duration-300">
            {Icon && <Icon className="w-6 h-6" />}
        </div>
        <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
      </div>
    );
  };
